package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() throws NoSuchMethodException, SecurityException, IllegalAccessException,
            IllegalArgumentException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        Method withTrailingDelimiterMethod = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterMethod.setAccessible(true);
        CSVFormat updatedCSVFormat = (CSVFormat) withTrailingDelimiterMethod.invoke(csvFormat, true);

        // Then
        assertTrue(updatedCSVFormat.getTrailingDelimiter());
    }
}
